"use client"

import { useCallback } from "react"
import { DeployTokenUI } from "./ui"
import {
  useDeployToken,
  type DeployTokenParams,
  type DeployTokenResult,
  type UseDeployTokenOptions,
} from "./use-deploy-token"

// ---------------------------------------------------------------------------
// Re-exports
// ---------------------------------------------------------------------------

export { DeployTokenUI, type DeployTokenUIProps, type DeployTokenFormState } from "./ui"
export {
  useDeployToken,
  type DeployTokenParams,
  type DeployTokenResult,
  type UseDeployTokenOptions,
  type UseDeployTokenReturn,
} from "./use-deploy-token"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface DeployTokenProps {
  /** Callback that executes the on-chain deploy action */
  onDeploy: (params: DeployTokenParams) => Promise<DeployTokenResult>
  /** Callback on successful deployment */
  onSuccess?: (result: DeployTokenResult) => void
  /** Callback on error */
  onError?: (error: Error) => void
  /** Default form values */
  defaults?: UseDeployTokenOptions
  /** Optional CSS class name */
  className?: string
  /** Callback to handle external links (e.g. open in system browser from a WebView) */
  onExternalLink?: (url: string) => void
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

/**
 * Composed BSV21 token deploy block wiring the `useDeployToken` hook
 * to the `DeployTokenUI` presentation component.
 *
 * Pass an `onDeploy` handler that calls the underlying deploy action
 * (e.g. `deployBsv21Token` from `@1sat/core`) and return a result
 * containing `{ txid }` or `{ error }`.
 *
 * @example
 * ```tsx
 * import { DeployToken } from "@/components/blocks/deploy-token"
 * import { deployBsv21Token } from "@1sat/core"
 *
 * <DeployToken
 *   onDeploy={async (params) => {
 *     const tx = await deployBsv21Token({
 *       symbol: params.symbol,
 *       decimals: params.decimals,
 *       icon: { dataB64: params.iconBase64, contentType: params.iconContentType },
 *       initialDistribution: { address: myAddress, tokens: Number(params.maxSupply) },
 *       destinationAddress: myAddress,
 *       utxos: paymentUtxos,
 *     })
 *     return { txid: tx.id("hex") }
 *   }}
 *   onSuccess={(r) => console.log("Deployed:", r.txid)}
 * />
 * ```
 */
export function DeployToken({
  onDeploy,
  onSuccess,
  onError,
  defaults,
  className,
  onExternalLink,
}: DeployTokenProps) {
  const token = useDeployToken(defaults)

  const handleDeploy = useCallback(() => {
    void token.deploy(async (params) => {
      const result = await onDeploy(params)

      if (result.error) {
        onError?.(new Error(result.error))
      } else {
        onSuccess?.(result)
      }

      return result
    })
  }, [token.deploy, onDeploy, onSuccess, onError])

  return (
    <DeployTokenUI
      form={token.form}
      onSymbolChange={token.setSymbol}
      onMaxSupplyChange={token.setMaxSupply}
      onDecimalsChange={token.setDecimals}
      onIconSelect={token.selectIcon}
      onIconRemove={token.removeIcon}
      onDeploy={handleDeploy}
      isDeploying={token.isDeploying}
      feeEstimate={token.feeEstimate}
      resultTxid={token.resultTxid}
      errorMessage={token.errorMessage}
      isValid={token.isValid}
      className={className}
      onExternalLink={onExternalLink}
    />
  )
}

"use client"

import { useCallback, type ChangeEvent } from "react"
import {
  AlertCircle,
  CheckCircle2,
  ExternalLink,
  Image as ImageIcon,
  Loader2,
  Rocket,
  Upload,
  X,
} from "lucide-react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Separator } from "@/components/ui/separator"
import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface DeployTokenFormState {
  /** Token symbol */
  symbol: string
  /** Maximum supply (whole tokens) */
  maxSupply: string
  /** Decimal precision (0-18) */
  decimals: string
  /** Icon file for inscription */
  iconFile: File | null
  /** Preview URL for the icon */
  iconPreviewUrl: string | null
}

export interface DeployTokenUIProps {
  /** Current form state */
  form: DeployTokenFormState
  /** Callback to update symbol */
  onSymbolChange: (value: string) => void
  /** Callback to update max supply */
  onMaxSupplyChange: (value: string) => void
  /** Callback to update decimals */
  onDecimalsChange: (value: string) => void
  /** Callback to set icon file */
  onIconSelect: (file: File) => void
  /** Callback to remove the icon */
  onIconRemove: () => void
  /** Callback to trigger deploy */
  onDeploy: () => void
  /** Whether a deploy is in progress */
  isDeploying: boolean
  /** Fee estimate in satoshis */
  feeEstimate: number
  /** Deploy result txid */
  resultTxid: string | null
  /** Deploy error message */
  errorMessage: string | null
  /** Whether the form is valid for submission */
  isValid: boolean
  /** Optional CSS class name */
  className?: string
  /** Callback to handle external links (e.g. open in system browser from a WebView) */
  onExternalLink?: (url: string) => void
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function formatNumber(value: string): string {
  const num = Number(value)
  if (Number.isNaN(num)) return value
  return num.toLocaleString()
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

/**
 * Pure presentation component for BSV21 token deployment.
 *
 * Renders the form fields (symbol, icon upload, max supply, decimals),
 * fee estimate, and deploy button. All state management is handled by
 * the parent via props.
 */
export function DeployTokenUI({
  form,
  onSymbolChange,
  onMaxSupplyChange,
  onDecimalsChange,
  onIconSelect,
  onIconRemove,
  onDeploy,
  isDeploying,
  feeEstimate,
  resultTxid,
  errorMessage,
  isValid,
  className,
  onExternalLink,
}: DeployTokenUIProps) {
  const handleIconInput = useCallback(
    (e: ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0]
      if (!file) return
      if (!file.type.startsWith("image/")) return
      onIconSelect(file)
    },
    [onIconSelect]
  )

  return (
    <Card className={cn("w-full", className)}>
      <CardHeader>
        <CardTitle>Deploy New Token</CardTitle>
        <CardDescription>
          Deploy a BSV21 fungible token. All tokens are minted to your wallet on
          deployment.
        </CardDescription>
      </CardHeader>

      <CardContent className="flex flex-col gap-6">
        {/* Symbol */}
        <div className="flex flex-col gap-2">
          <div className="flex items-center justify-between">
            <Label htmlFor="deploy-token-symbol">Symbol</Label>
            <span className="text-xs text-muted-foreground">
              Not required to be unique
            </span>
          </div>
          <Input
            id="deploy-token-symbol"
            placeholder="e.g. MYTOKEN"
            value={form.symbol}
            maxLength={32}
            onKeyDown={(e) => {
              if (e.key === " ") e.preventDefault()
            }}
            onChange={(e) => onSymbolChange(e.target.value.replace(/\s/g, ""))}
            aria-label="Token symbol"
          />
        </div>

        {/* Icon upload */}
        <div className="flex flex-col gap-2">
          <div className="flex items-center justify-between">
            <Label>Token Icon</Label>
            <span className="text-xs text-muted-foreground">
              Square image recommended
            </span>
          </div>
          <div className="flex items-center gap-4">
            {form.iconPreviewUrl ? (
              <div className="relative size-10 flex-shrink-0 overflow-hidden rounded-lg border bg-muted">
                <img
                  src={form.iconPreviewUrl}
                  alt="Token icon preview"
                  className="h-full w-full object-cover"
                />
                <Button
                  type="button"
                  variant="destructive"
                  size="icon"
                  className="absolute -right-1 -top-1 size-5"
                  onClick={onIconRemove}
                  aria-label="Remove icon"
                >
                  <X data-icon="inline-start" />
                </Button>
              </div>
            ) : (
              <div className="flex size-10 flex-shrink-0 items-center justify-center rounded-lg border border-dashed bg-muted/50">
                <ImageIcon className="size-5 text-muted-foreground/50" />
              </div>
            )}
            <div className="flex-1">
              <Label
                htmlFor="deploy-token-icon"
                className="flex h-10 w-full cursor-pointer items-center justify-center gap-2 rounded-md border px-4 py-2 text-sm transition-colors hover:bg-muted/50"
              >
                <Upload className="size-4" />
                {form.iconFile ? "Change Icon" : "Select Image"}
              </Label>
              <input
                type="file"
                id="deploy-token-icon"
                accept="image/*"
                className="sr-only"
                onChange={handleIconInput}
              />
            </div>
          </div>
        </div>

        {/* Max Supply + Decimals row */}
        <div className="grid grid-cols-2 gap-4">
          <div className="flex flex-col gap-2">
            <div className="flex items-center justify-between">
              <Label htmlFor="deploy-token-supply">Max Supply</Label>
              <span className="text-xs text-muted-foreground">
                Whole tokens
              </span>
            </div>
            <Input
              id="deploy-token-supply"
              type="text"
              inputMode="numeric"
              placeholder="21000000"
              value={form.maxSupply}
              onChange={(e) =>
                onMaxSupplyChange(e.target.value.replace(/[^0-9]/g, ""))
              }
              aria-label="Maximum token supply"
            />
            {form.maxSupply && (
              <p className="text-xs text-muted-foreground">
                {formatNumber(form.maxSupply)} tokens
              </p>
            )}
          </div>

          <div className="flex flex-col gap-2">
            <div className="flex items-center justify-between">
              <Label htmlFor="deploy-token-decimals">Decimals</Label>
              <span className="text-xs text-muted-foreground">0-18</span>
            </div>
            <Input
              id="deploy-token-decimals"
              type="number"
              min={0}
              max={18}
              placeholder="8"
              value={form.decimals}
              onChange={(e) => onDecimalsChange(e.target.value)}
              aria-label="Decimal precision"
            />
          </div>
        </div>

        {/* Fee estimate */}
        {isValid && (
          <>
            <Separator />
            <div className="flex items-center justify-between rounded-md border bg-muted/50 px-4 py-3">
              <span className="text-sm text-muted-foreground">
                Estimated deploy fee
              </span>
              <Badge variant="secondary">
                ~{feeEstimate.toLocaleString()} sats
              </Badge>
            </div>
          </>
        )}

        {/* Success */}
        {resultTxid && (
          <div className="flex items-start gap-3 rounded-md border border-primary/20 bg-primary/5 p-4">
            <CheckCircle2 className="mt-0.5 size-5 flex-shrink-0 text-primary" />
            <div className="min-w-0 flex flex-col gap-1">
              <p className="text-sm font-medium">Token deployed successfully</p>
              {onExternalLink ? (
                <button
                  type="button"
                  onClick={() => onExternalLink(`https://whatsonchain.com/tx/${resultTxid}`)}
                  className="inline-flex items-center gap-1 transition-colors hover:text-foreground"
                >
                  <Badge variant="outline" className="max-w-full truncate text-xs font-mono">
                    {resultTxid}
                  </Badge>
                  <ExternalLink className="size-3 flex-shrink-0" />
                </button>
              ) : (
                <a
                  href={`https://whatsonchain.com/tx/${resultTxid}`}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-flex items-center gap-1 transition-colors hover:text-foreground"
                >
                  <Badge variant="outline" className="max-w-full truncate text-xs font-mono">
                    {resultTxid}
                  </Badge>
                  <ExternalLink className="size-3 flex-shrink-0" />
                </a>
              )}
            </div>
          </div>
        )}

        {/* Error */}
        {errorMessage && (
          <div className="flex items-start gap-3 rounded-md border border-destructive/20 bg-destructive/5 p-4">
            <AlertCircle className="mt-0.5 size-5 flex-shrink-0 text-destructive" />
            <div className="flex flex-col gap-1">
              <p className="text-sm font-medium">Deployment failed</p>
              <p className="text-xs text-muted-foreground">{errorMessage}</p>
            </div>
          </div>
        )}
      </CardContent>

      <CardFooter>
        <Button
          className="w-full"
          onClick={onDeploy}
          disabled={!isValid || isDeploying}
          aria-busy={isDeploying}
        >
          {isDeploying ? (
            <>
              <Loader2 className="animate-spin" data-icon="inline-start" />
              Deploying...
            </>
          ) : (
            <>
              <Rocket data-icon="inline-start" />
              Deploy Token
            </>
          )}
        </Button>
      </CardFooter>
    </Card>
  )
}

import { useCallback, useMemo, useState } from "react"
import type { DeployTokenFormState } from "./ui"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Parameters passed to the onDeploy callback */
export interface DeployTokenParams {
  /** Token symbol */
  symbol: string
  /** Maximum supply as a string (raw integer, no separators) */
  maxSupply: string
  /** Decimal precision (0-18) */
  decimals: number
  /** Base64-encoded icon image content */
  iconBase64: string
  /** MIME type of the icon image */
  iconContentType: string
}

/** Result returned from the deploy callback */
export interface DeployTokenResult {
  /** Transaction ID of the deploy inscription */
  txid?: string
  /** Raw transaction hex */
  rawtx?: string
  /** Error message if deployment failed */
  error?: string
}

export interface UseDeployTokenOptions {
  /** Default symbol value */
  defaultSymbol?: string
  /** Default max supply value */
  defaultMaxSupply?: string
  /** Default decimal precision */
  defaultDecimals?: number
}

export interface UseDeployTokenReturn {
  /** Current form state for the UI */
  form: DeployTokenFormState
  /** Whether the form is valid for submission */
  isValid: boolean
  /** Whether a deploy is in progress */
  isDeploying: boolean
  /** Estimated fee in satoshis */
  feeEstimate: number
  /** Deploy result txid */
  resultTxid: string | null
  /** Error message */
  errorMessage: string | null
  /** Update the symbol */
  setSymbol: (value: string) => void
  /** Update max supply */
  setMaxSupply: (value: string) => void
  /** Update decimals */
  setDecimals: (value: string) => void
  /** Select an icon file */
  selectIcon: (file: File) => void
  /** Remove the icon */
  removeIcon: () => void
  /** Execute the deploy action */
  deploy: (
    handler: (params: DeployTokenParams) => Promise<DeployTokenResult>
  ) => Promise<void>
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function fileToBase64(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader()
    reader.onload = () => {
      const result = reader.result
      if (typeof result !== "string") {
        reject(new Error("Failed to read file"))
        return
      }
      const base64 = result.split(",")[1]
      if (!base64) {
        reject(new Error("Failed to encode file as base64"))
        return
      }
      resolve(base64)
    }
    reader.onerror = () => reject(new Error("Failed to read file"))
    reader.readAsDataURL(file)
  })
}

/**
 * Estimate the deploy fee.
 *
 * A BSV21 deploy+mint inscription includes the JSON payload plus
 * the icon image data. The estimate accounts for the base transaction
 * overhead plus ~0.5 sat per byte of icon data.
 */
function estimateDeployFee(iconSize: number): number {
  const baseFee = 100 // base tx overhead for deploy inscription
  const iconFee = Math.ceil(iconSize * 0.5)
  return baseFee + iconFee
}

function parseDecimals(value: string): number {
  if (value === "") return 8
  const parsed = Number.parseInt(value, 10)
  if (Number.isNaN(parsed)) return 8
  return Math.max(0, Math.min(18, parsed))
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

/**
 * Manages form state, validation, icon handling, fee estimation, and deploy
 * execution for a BSV21 token deployment.
 *
 * The hook is pure logic with no UI. Pair it with `DeployTokenUI` for
 * the presentation layer.
 *
 * @example
 * ```ts
 * const token = useDeployToken({ defaultMaxSupply: "21000000" })
 *
 * // In the deploy handler:
 * token.deploy(async (params) => {
 *   const config: DeployBsv21TokenConfig = {
 *     symbol: params.symbol,
 *     decimals: params.decimals,
 *     icon: { dataB64: params.iconBase64, contentType: params.iconContentType },
 *     initialDistribution: { address: myAddress, tokens: Number(params.maxSupply) },
 *     destinationAddress: myAddress,
 *     utxos: paymentUtxos,
 *   }
 *   const tx = await deployBsv21Token(config)
 *   return { txid: tx.id("hex") }
 * })
 * ```
 */
export function useDeployToken(
  options: UseDeployTokenOptions = {}
): UseDeployTokenReturn {
  const {
    defaultSymbol = "",
    defaultMaxSupply = "21000000",
    defaultDecimals = 8,
  } = options

  // Form fields
  const [symbol, setSymbol] = useState(defaultSymbol)
  const [maxSupply, setMaxSupply] = useState(defaultMaxSupply)
  const [decimals, setDecimals] = useState(
    defaultDecimals === 8 ? "" : String(defaultDecimals)
  )
  const [iconFile, setIconFile] = useState<File | null>(null)
  const [iconPreviewUrl, setIconPreviewUrl] = useState<string | null>(null)

  // Execution state
  const [isDeploying, setIsDeploying] = useState(false)
  const [resultTxid, setResultTxid] = useState<string | null>(null)
  const [errorMessage, setErrorMessage] = useState<string | null>(null)

  // Derived state
  const isValid = useMemo(() => {
    if (!symbol.trim()) return false
    if (!iconFile) return false
    if (!maxSupply || maxSupply === "0") return false
    const dec = parseDecimals(decimals)
    if (dec < 0 || dec > 18) return false
    return true
  }, [symbol, iconFile, maxSupply, decimals])

  const feeEstimate = useMemo(() => {
    if (!iconFile) return 0
    return estimateDeployFee(iconFile.size)
  }, [iconFile])

  const form: DeployTokenFormState = useMemo(
    () => ({
      symbol,
      maxSupply,
      decimals,
      iconFile,
      iconPreviewUrl,
    }),
    [symbol, maxSupply, decimals, iconFile, iconPreviewUrl]
  )

  // Icon handlers
  const selectIcon = useCallback(
    (file: File) => {
      if (iconPreviewUrl) {
        URL.revokeObjectURL(iconPreviewUrl)
      }
      setIconFile(file)
      setIconPreviewUrl(URL.createObjectURL(file))
      setResultTxid(null)
      setErrorMessage(null)
    },
    [iconPreviewUrl]
  )

  const removeIcon = useCallback(() => {
    if (iconPreviewUrl) {
      URL.revokeObjectURL(iconPreviewUrl)
    }
    setIconFile(null)
    setIconPreviewUrl(null)
  }, [iconPreviewUrl])

  // Deploy execution
  const deploy = useCallback(
    async (
      handler: (params: DeployTokenParams) => Promise<DeployTokenResult>
    ) => {
      if (!isValid || !iconFile) return

      setIsDeploying(true)
      setErrorMessage(null)
      setResultTxid(null)

      try {
        const iconBase64 = await fileToBase64(iconFile)
        const params: DeployTokenParams = {
          symbol: symbol.trim(),
          maxSupply,
          decimals: parseDecimals(decimals),
          iconBase64,
          iconContentType: iconFile.type || "image/png",
        }

        const result = await handler(params)

        if (result.error) {
          setErrorMessage(result.error)
        } else if (result.txid) {
          setResultTxid(result.txid)
        }
      } catch (err) {
        const message =
          err instanceof Error ? err.message : "Token deployment failed"
        setErrorMessage(message)
      } finally {
        setIsDeploying(false)
      }
    },
    [isValid, iconFile, symbol, maxSupply, decimals]
  )

  return {
    form,
    isValid,
    isDeploying,
    feeEstimate,
    resultTxid,
    errorMessage,
    setSymbol,
    setMaxSupply,
    setDecimals,
    selectIcon,
    removeIcon,
    deploy,
  }
}
